async function transaction(fn) {
  const client = await pool.connect();
  try {
    await client.query('BEGIN');
    const result = await fn(client);
    await client.query('COMMIT');
    return result;
  } catch (err) {
    try {
      await client.query('ROLLBACK');
    } catch {}
    throw err;
  } finally {
    client.release();
  }
}

async function createOrderWithItems({ user_id, items, status = 'pending' }) {
  return transaction(async (client) => {
    const total = items.reduce((sum, item) => sum + Number(item.unit_price) * Number(item.quantity), 0);

    const orderRes = await client.query(
      `INSERT INTO orders (user_id, status, total, updated_at)
       VALUES ($1, $2, $3, NOW())
       RETURNING *`,
      [user_id, status, total]
    );

    const order = orderRes.rows[0];

    const insertedItems = [];
    for (const item of items) {
      const itemRes = await client.query(
        `INSERT INTO order_items (order_id, product_id, quantity, unit_price, updated_at)
         VALUES ($1, $2, $3, $4, NOW())
         RETURNING *`,
        [order.id, item.product_id, item.quantity, item.unit_price]
      );
      insertedItems.push(itemRes.rows[0]);
    }

    return { order, items: insertedItems };
  });
}

